--- 原皮的品质
local defaultSkinQuality = 3

local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxHeroSkinCtrl:LxBaseCtrl
local LxHeroSkinCtrl = classX("LxHeroSkinCtrl", LxBaseCtrl)

function LxHeroSkinCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxHeroSkinCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end



function LxHeroSkinCtrl:GetParseHeroSkinRef(refId)
    if not self._parseHeroSkinRefMap then
        self._parseHeroSkinRefMap = {}
    end
    local parseHeroSkinRef = self._parseHeroSkinRefMap[refId]
    if not parseHeroSkinRef then
        local ref = GameTable.CharacterSkinRef[refId]
        if ref then
            parseHeroSkinRef = {
                refId = refId,
                skinQuality = ref.skinQuality,
                hero = ref.hero,
                --- 对本英雄加成
                attr = LxDataHelper.ParseAttrList(ref.attr),
                --- 对全部英雄加成
                attr1 = LxDataHelper.ParseAttrList(ref.attr1),
                addexp = LxDataHelper.ParseItem(ref.addexp),
                skinItem = ref.skinItem,
            }
            self._parseHeroSkinRefMap[refId] = parseHeroSkinRef
        end
    end
    return parseHeroSkinRef
end



---@param heroObj LxHeroObj
function LxHeroSkinCtrl:GetHeroSkinListByHeroObj(heroObj)
    local resultList = {}
    local skinId
    local parseSkinRef
    ---@type LxHeroSkinObj
    local skinObj
    local heroRefId = heroObj.refId
    local heroEffectIds = CtrlCenter.Hero:GetHeroAllSkinIdList(heroRefId)
    for i,v in ipairs(heroEffectIds) do
        skinId = v.refId
        parseSkinRef = self:GetParseHeroSkinRef(skinId)
        if parseSkinRef then
            skinObj = ModuleCenter.HeroSkin:GetHeroSkinObj(skinId)
            local hasSkinData = skinObj ~= nil
            local isCanAct = false
            if not hasSkinData then
                isCanAct = ModuleCenter.Item:GetItemCount(parseSkinRef.skinItem) > 0
                if not isCanAct then
                    isCanAct = CtrlCenter.Item:CheckHeroSkinTimeIsEnough(heroRefId)
                end
            end
            table.insert(resultList,{
                effectId = skinId,
                skinRef = parseSkinRef,
                skinObj = skinObj,
                hasSkinData = hasSkinData,
                isCanAct = isCanAct,
                isDefault = false,
                isHero = true,
            })
        elseif v.isDefault then
            -- 默认的皮肤，自己构造数据显示
            skinObj = self:_GetCommonHeroObj(skinId)
            parseSkinRef = self:_GetCommonSkinRef(skinId,heroRefId)
            table.insert(resultList,{
                effectId = skinId,
                skinRef = parseSkinRef,
                skinObj = skinObj,
                hasSkinData = true,
                isCanAct = false,
                isDefault = true,
                isHero = true,
            })
        end
    end
    return resultList
end


function LxHeroSkinCtrl:GetHeroSkinListBySkinId(skinRefId)
    local resultList = {}
    local heroType = LxDataHelper.GetHeroEff2HeroType(skinRefId)
    if heroType and heroType > 0 then
        local heroSkinModule = ModuleCenter.HeroSkin
        local skinId,parseSkinRef
        ---@type LxHeroSkinObj
        local skinObj
        local heroEffectIds = CtrlCenter.Hero:GetHeroAllSkinIdList(heroType)
        for i,v in ipairs(heroEffectIds) do
            skinId = v.refId
            skinObj = heroSkinModule:GetHeroSkinObj(skinId)
            parseSkinRef = self:GetParseHeroSkinRef(skinId)
            if v.isDefault then
                -- 默认的皮肤，自己构造数据显示
                skinObj = self:_GetCommonHeroObj(skinId)
                parseSkinRef = self:_GetCommonSkinRef(skinId,heroType)
                table.insert(resultList,{
                    effectId = skinId,
                    skinRef = parseSkinRef,
                    skinObj = skinObj,
                    hasSkinData = true,
                    isCanAct = false,
                    isDefault = true,
                })
            else
                local hasSkinData = skinObj ~= nil
                local isCanAct = false
                if not hasSkinData and parseSkinRef then
                    isCanAct = ModuleCenter.Item:GetItemCount(parseSkinRef.skinItem) > 0
                    if not isCanAct then
                        isCanAct = CtrlCenter.Item:CheckHeroSkinTimeIsEnough(heroType)
                    end
                end
                table.insert(resultList,{
                    effectId = skinId,
                    skinRef = parseSkinRef,
                    skinObj = skinObj,
                    hasSkinData = hasSkinData,
                    isCanAct = isCanAct,
                    isDefault = false,
                })
            end
        end
    end
    return resultList
end

function LxHeroSkinCtrl:_GetCommonHeroObj(skinId)
    return ModuleCenter.HeroSkin:NewHeroSkinObj({
        refId = skinId,
        endTime = -1,
    })
end

function LxHeroSkinCtrl:_GetCommonSkinRef(skinId,heroRefId)
    return {
        refId = skinId,
        skinQuality = LxDataHelper.GetHeroInitQuality(heroRefId) or defaultSkinQuality,
        hero = heroRefId,
        --- 对本英雄加成
        attr = {},
        --- 对全部英雄加成
        attr1 = {},
        addexp = nil,
        skinItem = 0,
    }
end


function LxHeroSkinCtrl:GetCollectHeroSkinInfo()
    local heroSkinModule = ModuleCenter.HeroSkin
    local curCollectNum = 0
    local allCollectNum = 0

    local skinObj
    local initHeroSkinTypesList = self:GetInitHeroSkinTypesList()
    for i,v in ipairs(initHeroSkinTypesList) do
        for idx,val in ipairs(v.heroSkin) do
            allCollectNum = allCollectNum + 1
            skinObj = heroSkinModule:GetHeroSkinObj(val.skinRefId)
            if skinObj ~= nil then
                curCollectNum = curCollectNum + 1
            end
        end
    end
    return {
        curCollectNum = curCollectNum,
        allCollectNum = allCollectNum,
        isCollectEnough = curCollectNum >= allCollectNum,
    }
end


function LxHeroSkinCtrl:GetInitHeroSkinTypesList()
    local initHeroSkinTypesList = self._initHeroSkinTypesList
    if not initHeroSkinTypesList then
        initHeroSkinTypesList = {}

        local initHeroSkinTypeMap = {}
        local heroSkin
        for k,v in pairs(GameTable.HeroSkinTypeRef) do
            local heroSkinList = {}
            heroSkin = string.split(v.heroSkin,"|")
            for idx,val in ipairs(heroSkin) do
                val = string.split(val,"=")
                table.insert(heroSkinList,{
                    heroRefId = checknumber(val[1]),
                    skinRefId = checknumber(val[2]),
                })
            end
            local data = {
                refId = k,
                name = I18nText(v.name),
                heroSkin = heroSkinList,
                reward = LxDataHelper.ParseItemList(v.reward),
            }
            table.insert(initHeroSkinTypesList,data)
            initHeroSkinTypeMap[k] = data
        end
        table.sort(initHeroSkinTypesList,function(a,b) return a.refId < b.refId end)
        self._initHeroSkinTypesList = initHeroSkinTypesList

        self._initHeroSkinTypeMap = initHeroSkinTypeMap
    end
    return initHeroSkinTypesList
end

function LxHeroSkinCtrl:GetInitHeroSkinTypeMap()
    if not self._initHeroSkinTypeMap then
        self:GetInitHeroSkinTypesList()
    end
    return self._initHeroSkinTypeMap
end

function LxHeroSkinCtrl:GetInitHeroSkinTypeDataById(id)
    local typeMap = self:GetInitHeroSkinTypeMap()
    return typeMap[id]
end


function LxHeroSkinCtrl:GetBookSkinList()
    local initHeroSkinTypesList = self:GetInitHeroSkinTypesList()

    local rewardIdx
    local rCollectNum = 0
    local rCollectAllNum = 0

    local heroSkinModule = ModuleCenter.HeroSkin
    local itemModule = ModuleCenter.Item
    local heroModule = ModuleCenter.Hero

    ---@type LxHeroSkinObj
    local skinObj
    local skinRefId,heroRefId
    local parseSkinRef,skinItem
    local isHasSkin,isCanAct,showAct
    local collectNum,collectAllNum
    local refId
    local list = {}
    for i,v in ipairs(initHeroSkinTypesList) do
        refId = v.refId
        ---@type LxHeroSkinSuitObj
        local heroSkinSuitObj = ModuleCenter.HeroSkin:GetHeroSkinSuitObjById(refId)
        local skinIdMap = heroSkinSuitObj and heroSkinSuitObj.skinIdMap or {}
        local recordRewardStateMap = {}
        local showSkinList = {}
        for idx,val in ipairs(v.heroSkin) do
            skinRefId = val.skinRefId
            heroRefId = val.heroRefId
            isCanAct = false
            showAct = false
            skinObj = heroSkinModule:GetHeroSkinObj(skinRefId)
            isHasSkin = skinObj ~= nil
            parseSkinRef = self:GetParseHeroSkinRef(skinRefId)
            if not isHasSkin then
                skinItem = parseSkinRef and parseSkinRef.skinItem
                if skinItem and skinItem > 0 then
                    showAct = itemModule:GetItemCount(skinItem) > 0
                end
                if showAct then
                    isCanAct = heroModule:IsHasHeroRefId(heroRefId)
                end
            else
                isHasSkin = skinObj:IsPermanent()
            end
            table.insert(showSkinList,{
                heroRefId = heroRefId,
                skinRefId = skinRefId,
                skinQuality = parseSkinRef and parseSkinRef.skinQuality or 5,
                skinObj = skinObj,
                isHasSkin = isHasSkin,
                ---@type boolean 红点显示用
                isCanAct = isCanAct,
                ---@type boolean 界面显示可激活
                showAct = showAct,
            })
            if skinIdMap[skinRefId] then
                recordRewardStateMap[idx] = true
            end
        end
        local isAllReward = self:CheckSkinAllRewardState(refId)
        local hasReward = self:CheckSkinHasReward(refId)
        if not rewardIdx and hasReward then
            rewardIdx = i
        end
        collectNum = self:GetSkinCollectNum(refId)
        collectAllNum = #v.heroSkin
        rCollectNum = rCollectNum + collectNum
        rCollectAllNum = rCollectAllNum + collectAllNum

        local showRewardList = {}
        ---@type V_Item[]
        local reward = v.reward
        for idx,val in ipairs(reward) do
            table.insert(showRewardList,{
                refId = val.refId,
                num = val.num,
                type = val.type,
                sel = recordRewardStateMap[idx]
            })
        end

        table.insert(list,{
            refId = refId,
            name = v.name,
            reward = showRewardList,
            hasReward = hasReward,
            isAllReward = isAllReward,
            showSkinList = showSkinList,
            collectNum = collectNum,
            collectAllNum = collectAllNum,
            isCollectFull = collectNum >= collectAllNum,
        })
    end
    local collectSchedule = rCollectNum / rCollectAllNum
    return list,rewardIdx,collectSchedule
end


---@return boolean 是否已经激活皮肤
function LxHeroSkinCtrl:CheckSkinIsAct(suitId,skinId)
    ---@type LxHeroSkinSuitObj
    local heroSkinSuitObj = ModuleCenter.HeroSkin:GetHeroSkinSuitObjById(suitId)
    if not heroSkinSuitObj then return false end
    return heroSkinSuitObj:CheckSkinIsAct(skinId)
end


---@return boolean 是否已领取的奖励的皮肤id
function LxHeroSkinCtrl:CheckSkinIsReward(suitId,skinId)
    ---@type LxHeroSkinSuitObj
    local heroSkinSuitObj = ModuleCenter.HeroSkin:GetHeroSkinSuitObjById(suitId)
    if not heroSkinSuitObj then return false end
    return heroSkinSuitObj:CheckSkinIsReward(skinId)
end

---@return boolean 是否已经全部领取完
function LxHeroSkinCtrl:CheckSkinAllRewardState(suitId)
    ---@type LxHeroSkinSuitObj
    local heroSkinSuitObj = ModuleCenter.HeroSkin:GetHeroSkinSuitObjById(suitId)
    if not heroSkinSuitObj then return false end

    local typeData = self:GetInitHeroSkinTypeDataById(suitId)
    if not typeData then return false end

    local isAllReward = true
    for i,v in ipairs(typeData.heroSkin) do
        if not heroSkinSuitObj:CheckSkinIsReward(v.skinRefId) then
            isAllReward = false
            break
        end
    end
    return isAllReward
end


---@return boolean 是否有未领取的皮肤奖励
function LxHeroSkinCtrl:CheckSkinHasReward(suitId)
    ---@type LxHeroSkinSuitObj
    local heroSkinSuitObj = ModuleCenter.HeroSkin:GetHeroSkinSuitObjById(suitId)
    if not heroSkinSuitObj then return false end

    local actNum = 0
    for k,v in pairs(heroSkinSuitObj.heroRefIdMap) do
        actNum = actNum + 1
    end

    local alreadyNum = 0
    for k,v in pairs(heroSkinSuitObj.skinIdMap) do
        alreadyNum = alreadyNum + 1
    end

    return actNum > alreadyNum
end

---@return number 获取收集数量
function LxHeroSkinCtrl:GetSkinCollectNum(suitId)
    ---@type LxHeroSkinSuitObj
    local heroSkinSuitObj = ModuleCenter.HeroSkin:GetHeroSkinSuitObjById(suitId)
    if not heroSkinSuitObj then return 0 end

    local actNum = 0
    for k,v in pairs(heroSkinSuitObj.heroRefIdMap) do
        actNum = actNum + 1
    end
    return actNum
end



---@return LxHeroObj
function LxHeroSkinCtrl:GetHeroObjByHeroSkin(heroRefId)
    local heroList = ModuleCenter.Hero:GetRefHeroList(heroRefId)
    if #heroList < 1 then return end

    table.sort(heroList,function(a,b)
        local starA,starB = a.star,b.star
        if starA ~= starB then return starA > starB end
        local levelA,levelB = a.level,b.level
        if levelA ~= levelB then return levelA > levelB end
        return a.id > b.id
    end)
    return heroList[1]
end




function LxHeroSkinCtrl:CheckHeroSkinRP()
    ---@type LxFormationObj[]
    local battleList = ModuleCenter.Battle:GetFormationList(BattleType.Adventure) or {}
    if #battleList < 1 then return false end
    local heroList = ModuleCenter.Hero:GetHeroList()
    ---@type LxHeroObj
    local heroObj
    for i,v in ipairs(battleList) do
        for index,unitPosObj in pairs(v.positions) do
            if string.isvalid(unitPosObj.id) then
                heroObj = heroList[unitPosObj.id]
                if heroObj then
                    if self:CheckHeroSkinRPByHeroObj(heroObj) then
                        return true
                    end
                end
            end
        end
    end
    return false
end

---@param heroObj LxHeroObj
function LxHeroSkinCtrl:CheckHeroSkinRPByHeroObj(heroObj)
    if not heroObj then return false end
    local skinList = self:GetHeroSkinListByHeroObj(heroObj)
    if not skinList or #skinList < 1 then return false end
    for i,v in ipairs(skinList) do
        if v.isCanAct then
            return true
        end
    end
    return false
end


function LxHeroSkinCtrl:CheckSkinBookRP()
    local initHeroSkinTypesList = self:GetInitHeroSkinTypesList() or {}
    for i,v in ipairs(initHeroSkinTypesList) do
        if self:CheckSkinHasReward(v.refId) then
            return true
        end
    end
    return false
end


return LxHeroSkinCtrl